solutions.cpp:
// Solution.cpp
#include <iostream>
using namespace std;

class Solution {
public:
    ListNode* insertAtHead(ListNode* head, int value) {
        ListNode* newHead = new ListNode(value);
        newHead->next = head;
        return newHead;
    }
};

int main() {
    ListNode head(1, ListNode(2, ListNode(3)));
    int value = 0;
    Solution s;
    ListNode* result = s.insertAtHead(&head, value);
    while (result != nullptr)
        cout << result->val << ' ';
        result = result->next;
    return 0;
}
